func maskPreproc(content string) string {
	lines := strings.SplitAfter(content, "\n")
	for i, line := range lines {
		text := strings.TrimRight(line, "\r\n")
		if strings.HasPrefix(strings.TrimSpace(text), "#") {
			lines[i] = strings.Repeat(" ", len(text)) + line[len(text):]
		}
	}
	return strings.Join(lines, "")
}

func main() {
	mask := false
	args := os.Args[1:]
	if args[0] == "-mask" {
		mask = true
		args = args[1:]
	}
	for _, f := range args {
		src, err := os.ReadFile(f)
		if err != nil {
			panic(err)
		}
		if mask {
			src = []byte(maskPreproc(string(src)))
		}
		p := sitter.NewParser()
		p.SetLanguage(csharp.GetLanguage())
		tree, err := p.ParseCtx(context.Background(), nil, src)
		if err != nil {
			panic(err)
		}
		root := tree.RootNode()
		count := 0
		var walk func(n *sitter.Node)
		var firstErrs []string
		walk = func(n *sitter.Node) {
			if n.Type() == "ERROR" || n.IsMissing() {
				count++
				if len(firstErrs) < 10 {
					end := int(n.StartByte()) + 80
					if int(n.EndByte()) < end {
						end = int(n.EndByte())
					}
					firstErrs = append(firstErrs, fmt.Sprintf("line %d: %q", n.StartPoint().Row+1, snippetOf(src, int(n.StartByte()), end)))
				}
			}
			for i := 0; i < int(n.ChildCount()); i++ {
				walk(n.Child(i))
			}
		}
		walk(root)
		fmt.Printf("%s: %d ERROR/MISSING nodes\n", f, count)
		for _, e := range firstErrs {
			fmt.Println("  ", e)
		}
	}
}

func snippetOf(src []byte, a, b int) string { return string(src[a:b]) }
